{
  "summary": "A high-intensity radial burst of magenta and white streaks, simulating a sharp ninja strike impact. It uses additive blending and elongated particles to create a 'spiky' starburst effect that rapidly expands and fades.",
  "duration_ms": 450,
  "palette": [
    "#FFFFFF",
    "#FF00FF",
    "#FF69B4",
    "#BA55D3"
  ],
  "particle_config": {
    "count": 45,
    "speed": {
      "min": 200,
      "max": 500
    },
    "lifespan": 350,
    "scale": {
      "start": 1.5,
      "end": 0
    },
    "stretch": 8,
    "blend_mode": "ADD",
    "easing": "Cubic.easeOut"
  },
  "typescript": "function createNinjaStrike(scene: Phaser.Scene, x: number, y: number) {
  if (!scene.textures.exists('vfx_dot')) {
    const graphics = scene.make.graphics({ x: 0, y: 0, add: false });
    graphics.fillStyle(0xffffff, 1);
    graphics.fillCircle(2, 2, 2);
    graphics.generateTexture('vfx_dot', 4, 4);
  }

  const emitter = scene.add.particles(x, y, 'vfx_dot', {
    speed: { min: 150, max: 550 },
    angle: { min: 0, max: 360 },
    lifespan: { min: 250, max: 400 },
    scaleX: { start: 6, end: 0 },
    scaleY: { start: 0.5, end: 0 },
    rotate: (p: any) => p.angle,
    tint: [0xffffff, 0xff00ff, 0xff77ff, 0xba55d3],
    blendMode: 'ADD',
    emitting: false
  });

  // Core flash
  const flash = scene.add.circle(x, y, 10, 0xffffff).setAlpha(1);
  scene.tweens.add({
    targets: flash,
    scale: 4,
    alpha: 0,
    duration: 200,
    onComplete: () => flash.destroy()
  });

  emitter.explode(50);
  scene.time.delayedCall(500, () => emitter.destroy());
}"
}
}
